INSERT INTO `wallpapers` VALUES (1,1,'奶油小猫午后','一只蜷在阳光里的奶油小猫，适合作为治愈系手机壁纸。','https://picsum.photos/id/1025/1440/2560','https://picsum.photos/id/1025/480/854','[\"萌宠\", \"治愈\", \"猫咪\"]',4.5,1,129,528,'咸虾米',1,'2026-03-23 12:48:58','2026-03-26 06:06:20'),(2,1,'软萌小狗出游','清爽背景下的小狗写真，适合锁屏和桌面。','https://picsum.photos/id/237/1440/2560','https://picsum.photos/id/237/480/854','[\"萌宠\", \"小狗\", \"清新\"]',4.0,1,96,412,'咸虾米',1,'2026-03-23 12:48:58','2026-03-24 02:44:36'),(3,2,'山湖清晨薄雾','远山和湖面被晨雾包裹，画面安静通透。','https://picsum.photos/id/1015/1440/2560','https://picsum.photos/id/1015/480/854','[\"风景\", \"山川\", \"自然\"]',1.0,1,211,836,'咸虾米',1,'2026-03-23 12:48:58','2026-03-26 02:53:45'),(4,2,'海边落日晚霞','暖色晚霞与海面层次分明，适合做锁屏封面。','https://picsum.photos/id/1011/1440/2560','https://picsum.photos/id/1011/480/854','[\"海边\", \"晚霞\", \"风景\"]',5.0,1,175,690,'咸虾米',1,'2026-03-23 12:48:58','2026-03-26 02:53:56'),(5,3,'元气少女幻想','偏明亮配色的二次元人物插画风格壁纸。','https://picsum.photos/id/1005/1440/2560','https://picsum.photos/id/1005/480/854','[\"二次元\", \"少女\", \"插画\"]',4.0,1,84,301,'咸虾米',1,'2026-03-23 12:48:58','2026-03-26 02:24:01'),(6,3,'夜空城市幻想','冷色系幻想城市画面，适合喜欢动漫氛围感的人。','https://picsum.photos/id/1039/1440/2560','https://picsum.photos/id/1039/480/854','[\"二次元\", \"幻想\", \"夜景\"]',4.0,1,102,355,'咸虾米',1,'2026-03-23 12:48:58','2026-03-26 02:28:05'),(7,4,'撞色几何光影','高饱和撞色与几何图形结合，视觉冲击感强。','https://picsum.photos/id/1060/1440/2560','https://picsum.photos/id/1060/480/854','[\"创意\", \"撞色\", \"几何\"]',4.0,1,73,264,'咸虾米',1,'2026-03-23 12:48:58','2026-03-26 02:27:42'),(8,4,'流体渐变艺术','适合极简风桌面的抽象色彩壁纸。','https://picsum.photos/id/1056/1440/2560','https://picsum.photos/id/1056/480/854','[\"创意\", \"渐变\", \"抽象\"]',4.6,19,88,320,'咸虾米',1,'2026-03-23 12:48:58','2026-03-23 12:52:15'),(9,5,'电竞霓虹赛场','霓虹灯感和速度感兼具的电竞风壁纸。','https://picsum.photos/id/1041/1440/2560','https://picsum.photos/id/1041/480/854','[\"游戏\", \"电竞\", \"霓虹\"]',4.0,1,119,447,'咸虾米',1,'2026-03-23 12:48:58','2026-03-25 05:47:41'),(10,5,'机甲战斗氛围','厚重色调与机械质感结合，适合游戏党。','https://picsum.photos/i